1242	// writeLoopEvent emits one structured JSONL line to sink describing a
1243	// milestone in an execute-bead loop run. Entries use the same envelope as
1244	// the Fizeau harness (session_id/seq/type/ts/data) so existing log
1245	// aggregators (FormatSessionLogLines, ddx server workers log) can parse
1246	// the stream uniformly. Errors are swallowed: structured logging must
1247	// never break the core execute-loop.
1248	func writeLoopEvent(sink io.Writer, sessionID, eventType string, data map[string]any, ts time.Time) {
1249		if sink == nil {
1250			return
1251		}
1252		if data == nil {
1253			data = map[string]any{}
1254		}
1255		entry := map[string]any{
1256			"session_id": sessionID,
1257			"type":       eventType,
1258			"ts":         ts.UTC().Format(time.RFC3339Nano),
1259			"data":       data,
1260		}
1261		line, err := json.Marshal(entry)
1262		if err != nil {
1263			return
1264		}
1265		_, _ = sink.Write(line)
1266		_, _ = sink.Write([]byte("\n"))
