1319	// adjudicateNoChanges runs the no-change adjudication step for a bead.
1320	// It returns (satisfied, evidence, err). When satisfied is true the bead
1321	// should be closed as already_satisfied with the evidence string. When false
1322	// retry suppression (cooldown) should be applied and the bead left open.
1323	//
1324	// If a SatisfactionChecker is configured it is called first. Otherwise:
1325	//   - When the report carries a specific rationale (cites a commit SHA or test
1326	//     name), the bead is closed as already_satisfied on the first occurrence.
1327	//   - Otherwise the default count-based rule applies (close after maxNoChangesBeforeClose).
1328	func (w *ExecuteBeadWorker) adjudicateNoChanges(ctx context.Context, beadID string, noChangesCount, maxNoChangesBeforeClose int, rationale, acceptance, issueType, projectRoot string) (bool, string, error) {
1329		if w.SatisfactionChecker != nil {
1330			return w.SatisfactionChecker.CheckSatisfied(ctx, beadID, noChangesCount)
1331		}
1332		candidate := false
1333		evidence := ""
1334		switch {
1335		case rationaleIsSpecific(rationale):
1336			candidate = true
1337			evidence = rationale
1338		case noChangesCount >= maxNoChangesBeforeClose:
1339			candidate = true
1340			evidence = fmt.Sprintf("no_changes on %d consecutive attempt(s); bead treated as already satisfied", noChangesCount)
1341		}
1342		if !candidate {
1343			return false, "", nil
1344		}
1345		// Tighten the gate: when AC names structural properties (test functions,
1346		// deleted files, removed struct fields), refuse already_satisfied unless
1347		// each property holds in the worktree / rationale. Prevents false closes
1348		// where a regression suite passes but the AC's specific contract is unmet.
1349		//
1350		// operator-prompt beads carry an auto-generated AC stub (the prompt body
1351		// IS the contract); the structural verifier does not apply and is
1352		// skipped per Story 15 §Implementation #1.
1353		if issueType != bead.IssueTypeOperatorPrompt {
1354			if claims := ParseACClaims(acceptance); len(claims) > 0 {
1355				if ok, why := VerifyACClaims(claims, projectRoot, rationale); !ok {
1356					return false, why, nil
1357				}
1358			}
1359		}
1360		return true, evidence, nil
1361	}
