1370	// classifyReviewError maps a reviewer error and partial result into one of the
1371	// four FEAT-022 §12 taxonomy classes. Resolution order:
1372	//  1. reviewRes.Error if it's already one of the canonical class identifiers
1373	//     (the reviewer set it explicitly — preferred path).
1374	//  2. The error string text (for backwards-compatible reviewers that only
1375	//     embed the class in their message).
1376	//  3. ErrReviewVerdictUnparseable as a fallback when the strict-parse error
1377	//     leaks through a reviewer that did not set Error.
1378	//  4. Default to transport (network/provider-side failure) when nothing else
1379	//     matches.
1380	func classifyReviewError(reviewErr error, reviewRes *ReviewResult) string {
1381		if reviewRes != nil {
1382			switch reviewRes.Error {
1383			case evidence.OutcomeReviewContextOverflow,
1384				evidence.OutcomeReviewProviderEmpty,
1385				evidence.OutcomeReviewUnparseable,
1386				evidence.OutcomeReviewTransport:
1387				return reviewRes.Error
1388			}
1389		}
1390		msg := ""
1391		if reviewErr != nil {
1392			msg = reviewErr.Error()
1393		}
1394		switch {
1395		case strings.Contains(msg, evidence.OutcomeReviewContextOverflow):
1396			return evidence.OutcomeReviewContextOverflow
1397		case strings.Contains(msg, evidence.OutcomeReviewProviderEmpty):
1398			return evidence.OutcomeReviewProviderEmpty
1399		case strings.Contains(msg, evidence.OutcomeReviewUnparseable):
1400			return evidence.OutcomeReviewUnparseable
1401		case strings.Contains(msg, evidence.OutcomeReviewTransport):
1402			return evidence.OutcomeReviewTransport
1403		case reviewErr != nil && strings.Contains(msg, ErrReviewVerdictUnparseable.Error()):
1404			return evidence.OutcomeReviewUnparseable
1405		}
1406		return evidence.OutcomeReviewTransport
1407	}
